    ref = list(map(int, f.read().split()))

fov = 900.0

# Let's find the correct floor parameters by sampling at many points
# and finding consistent (xoff, zoff, inv) for a given (d, freq)

# First, let's determine d and freq from the tile widths
# width = T * (y - 900) / d  where T = 1/freq
# So width / (y - 900) = T / d = 1/(freq * d)
# From earlier: width / (y - 900) ≈ 0.667
# So freq * d = 1 / 0.667 ≈ 1.5

# If d = 1.5, freq = 1.0 => product = 1.5 ✓
# If d = 0.75, freq = 2.0 => product = 1.5 ✓
# If d = 2.25, freq = 0.667 => product = 1.5

print("Testing floor parameters for consistency...")

def test_floor_params(d, freq, xoff, zoff, inv):
    """Test a single set of parameters on multiple y values"""
    matches = 0
    total = 0
    for y in [920, 950, 1000, 1100, 1200, 1300, 1400]:
        dy = -(y - 900.0) / fov
        if dy >= 0:
            continue
        Z = d / (-dy)
        for x in range(0, 2400, 50):
            i = (y*w + x)*3
            r = ref[i]
            if r != 152 and r != 67:
                continue
            actual = 1 if r == 152 else 0
            X = (x - 1200.0) * Z / fov
            ix = int(math.floor(X * freq + xoff))
            iz = int(math.floor(Z * freq + zoff))
            pred = (ix + iz + inv) & 1
            if pred == actual:
                matches += 1
            total += 1
    return matches / total if total > 0 else 0, matches, total

# Test the two most likely candidates
print("\nTesting d=1.5, freq=1.0 (product=1.5):")
for xoff in [i/4.0 for i in range(-4, 4)]:
    for zoff in [i/4.0 for i in range(-4, 4)]:
        for inv in [0, 1]:
            acc, m, t = test_floor_params(1.5, 1.0, xoff, zoff, inv)
            if acc > 0.9:
                print(f"  xoff={xoff:.2f}, zoff={zoff:.2f}, inv={inv}: {m}/{t} = {100*acc:.2f}%")

print("\nTesting d=0.75, freq=2.0 (product=1.5):")
